import React, { useEffect, useRef } from 'react';

const Hero = ({ toggleHover }) => {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);

  // DNA data for the hero section
  const dnaData = [
    { skill: 'React', color: '#00ffff' },
    { skill: 'Node.js', color: '#ff0080' },
    { skill: 'JavaScript', color: '#8000ff' },
    { skill: 'Python', color: '#00ff41' },
    { skill: 'CSS', color: '#0080ff' },
    { skill: 'MongoDB', color: '#ffff00' }
  ];

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    let time = 0;
    let particles = [];

    // Set canvas size
    const resizeCanvas = () => {
      canvas.width = canvas.offsetWidth * window.devicePixelRatio;
      canvas.height = canvas.offsetHeight * window.devicePixelRatio;
      ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    // Particle class
    class Particle {
      constructor() {
        this.x = Math.random() * canvas.offsetWidth;
        this.y = Math.random() * canvas.offsetHeight;
        this.size = Math.random() * 1.5 + 0.5;
        this.speedX = (Math.random() - 0.5) * 0.3;
        this.speedY = (Math.random() - 0.5) * 0.3;
        this.color = dnaData[Math.floor(Math.random() * dnaData.length)].color;
        this.opacity = Math.random() * 0.4 + 0.1;
      }

      update() {
        this.x += this.speedX;
        this.y += this.speedY;
        if (this.x < 0 || this.x > canvas.offsetWidth) this.speedX *= -1;
        if (this.y < 0 || this.y > canvas.offsetHeight) this.speedY *= -1;
      }

      draw() {
        ctx.save();
        ctx.globalAlpha = this.opacity;
        ctx.shadowBlur = 8;
        ctx.shadowColor = this.color;
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      }
    }

    // Initialize particles
    for (let i = 0; i < 30; i++) {
      particles.push(new Particle());
    }

    // Animation function
    const animate = () => {
      ctx.clearRect(0, 0, canvas.offsetWidth, canvas.offsetHeight);
      
      const centerX = canvas.offsetWidth / 2;
      const centerY = canvas.offsetHeight / 2;
      const radius = 60;
      const helixHeight = 200;

      // Draw DNA strands
      for (let i = 0; i < dnaData.length; i++) {
        const skill = dnaData[i];
        const angle1 = (time + i * 0.5) * 0.015;
        const angle2 = angle1 + Math.PI;
        
        const y1 = centerY - helixHeight/2 + (i / dnaData.length) * helixHeight;
        const y2 = y1;
        
        const x1 = centerX + Math.cos(angle1) * radius;
        const z1 = Math.sin(angle1) * radius;
        const x2 = centerX + Math.cos(angle2) * radius;
        const z2 = Math.sin(angle2) * radius;

        // 3D effect
        const scale1 = (z1 + radius) / (radius * 2);
        const scale2 = (z2 + radius) / (radius * 2);

        // Draw connecting line
        ctx.save();
        ctx.strokeStyle = skill.color;
        ctx.shadowBlur = 10;
        ctx.shadowColor = skill.color;
        ctx.lineWidth = 1.5;
        ctx.globalAlpha = 0.4;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();
        ctx.restore();

        // Draw nodes
        [
          { x: x1, y: y1, scale: scale1 },
          { x: x2, y: y2, scale: scale2 }
        ].forEach(({ x, y, scale }) => {
          const nodeSize = 4 * scale;
          
          ctx.save();
          ctx.shadowBlur = 15;
          ctx.shadowColor = skill.color;
          ctx.fillStyle = skill.color;
          ctx.globalAlpha = scale * 0.8;
          ctx.beginPath();
          ctx.arc(x, y, nodeSize, 0, Math.PI * 2);
          ctx.fill();
          ctx.restore();
        });
      }

      // Update and draw particles
      particles.forEach(particle => {
        particle.update();
        particle.draw();
      });

      time++;
      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, []);

  return (
    <section id="hero" className="reveal">
      <div className="hero-left">
        <div className="hero-eyebrow">
          <span className="hero-eyebrow-line"></span>
          <span>Full Stack Developer</span>
        </div>
        <h1 className="hero-name">
          Building<br />
          <em>Digital</em><br />
          Products
        </h1>
        <p className="hero-subtitle">
          I design and engineer web applications where clean code meets purposeful design — from pixel-perfect UIs to production-grade backends.
        </p>
        <div className="hero-cta">
          <a href="#projects" className="btn-primary" onMouseEnter={() => toggleHover(true)} onMouseLeave={() => toggleHover(false)}>
            View My Work
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><path d="M2 7h10M7 2l5 5-5 5" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round"/></svg>
          </a>
          <a href="#contact" className="btn-outline" onMouseEnter={() => toggleHover(true)} onMouseLeave={() => toggleHover(false)}>
            Get In Touch
          </a>
        </div>
      </div>

      <div className="hero-right">
        <div className="hero-dna-container">
          <canvas ref={canvasRef} className="hero-dna-canvas"></canvas>
          <div className="hero-dna-overlay">
            <div className="dna-title">Digital DNA</div>
            <div className="dna-skills">
              {dnaData.map((skill, index) => (
                <span key={index} className="dna-skill" style={{'--skill-color': skill.color}}>
                  {skill.skill}
                </span>
              ))}
            </div>
            <div className="dna-description">
              My coding genome - technologies that define my digital identity
            </div>
          </div>
        </div>
      </div>

      <div className="hero-scroll">
        <span>Scroll</span>
        <div className="scroll-line"></div>
      </div>
    </section>
  );
};

export default Hero;
